//! Runtime values generated by component style definitions.

use std::{borrow::Cow, fmt};

/// Error returned when a runtime CSS value fails validation.
#[derive(Clone, Debug, PartialEq, Eq, thiserror::Error)]
pub enum CssValueError {
	/// The supplied color is neither a supported named color nor a hexadecimal color.
	#[error("invalid CSS color `{value}`")]
	InvalidColor {
		/// The rejected value.
		value: String,
	},
}

fn finite(value: f64, wrapper: &str) -> f64 {
	assert!(value.is_finite(), "{wrapper} rejects non-finite values");
	value
}

fn write_decimal(value: f64, output: &mut String) {
	output.push_str(&value.to_string());
}

mod private {
	pub trait Sealed {}
}

/// Sealed serialization contract used by generated component-variable setters.
#[doc(hidden)]
pub trait StyleValue: private::Sealed {
	/// Writes exactly one validated CSS value.
	fn write_css_value(&self, output: &mut String);
	/// Returns the numeric value when this CSS value supports numeric constraints.
	fn numeric_value(&self) -> Option<f64>;
}

macro_rules! numeric_value {
	($name:ident, $wrapper:literal, $suffix:literal) => {
		#[doc = concat!("A finite runtime `", $wrapper, "` CSS value.")]
		#[derive(Clone, Copy, Debug, PartialEq)]
		pub struct $name(f64);

		impl $name {
			/// Creates a validated finite value.
			pub fn new(value: f64) -> Self {
				Self(finite(value, $wrapper))
			}
		}

		impl private::Sealed for $name {}

		impl StyleValue for $name {
			fn write_css_value(&self, output: &mut String) {
				write_decimal(self.0, output);
				output.push_str($suffix);
			}

			fn numeric_value(&self) -> Option<f64> {
				Some(self.0)
			}
		}

		impl fmt::Display for $name {
			fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
				let mut output = String::new();
				self.write_css_value(&mut output);
				formatter.write_str(&output)
			}
		}
	};
}

numeric_value!(CssPercentage, "CssPercentage", "%");
numeric_value!(CssNumber, "CssNumber", "");

/// A finite CSS length with a checked unit.
#[derive(Clone, Copy, Debug, PartialEq)]
pub struct CssLength {
	value: f64,
	unit: &'static str,
}

macro_rules! length_constructors {
	($(($name:ident, $unit:literal)),+ $(,)?) => {
		impl CssLength {
			$(
				#[doc = concat!("Creates a finite CSS length in `", $unit, "` units.")]
				pub fn $name(value: f64) -> Self {
					Self { value: finite(value, "CssLength"), unit: $unit }
				}
			)+
		}
	};
}

