/// A runtime integer CSS value.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct CssInteger(i64);

impl CssInteger {
	/// Creates an integer value.
	pub const fn new(value: i64) -> Self {
		Self(value)
	}
}

impl private::Sealed for CssInteger {}

impl StyleValue for CssInteger {
	fn write_css_value(&self, output: &mut String) {
		output.push_str(&self.0.to_string());
	}

	fn numeric_value(&self) -> Option<f64> {
		Some(self.0 as f64)
	}
}

impl fmt::Display for CssInteger {
	fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
		write!(formatter, "{}", self.0)
	}
}

/// A parsed hexadecimal or named CSS color.
#[derive(Clone, Debug, PartialEq, Eq, Hash)]
pub struct CssColor(String);

impl CssColor {
	/// Parses one checked CSS color value.
	pub fn parse(value: &str) -> Result<Self, CssValueError> {
		let normalized = value.to_ascii_lowercase();
		let valid = valid_hex_color(&normalized) || NAMED_COLORS.contains(&normalized.as_str());
		valid
			.then_some(Self(normalized))
			.ok_or_else(|| CssValueError::InvalidColor {
				value: value.to_owned(),
			})
	}
}

impl private::Sealed for CssColor {}

impl StyleValue for CssColor {
	fn write_css_value(&self, output: &mut String) {
		output.push_str(&self.0);
	}

	fn numeric_value(&self) -> Option<f64> {
		None
	}
}

impl fmt::Display for CssColor {
	fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
		formatter.write_str(&self.0)
	}
}

fn valid_hex_color(value: &str) -> bool {
	let Some(digits) = value.strip_prefix('#') else {
		return false;
	};
	matches!(digits.len(), 3 | 4 | 6 | 8) && digits.bytes().all(|byte| byte.is_ascii_hexdigit())
}

