/// One generated scoped class name.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub struct ClassToken(&'static str);

impl ClassToken {
	/// Creates a generated class token.
	#[doc(hidden)]
	pub const fn new(value: &'static str) -> Self {
		Self(value)
	}

	/// Returns the scoped class name.
	pub const fn as_str(&self) -> &'static str {
		self.0
	}
}

/// An ordered composition of generated and legacy class names.
#[derive(Clone, Debug, PartialEq, Eq)]
pub struct ClassList(String);

impl ClassList {
	/// Returns the composed class attribute value.
	pub fn as_str(&self) -> &str {
		&self.0
	}

	fn push(&mut self, value: &str) {
		if value.is_empty() {
			return;
		}
		if !self.0.is_empty() {
			self.0.push(' ');
		}
		self.0.push_str(value);
	}
}

impl std::ops::Add<ClassToken> for ClassToken {
	type Output = ClassList;

	fn add(self, rhs: ClassToken) -> Self::Output {
		let mut list = ClassList(self.0.to_owned());
		list.push(rhs.0);
		list
	}
}

impl std::ops::Add<&'static str> for ClassToken {
	type Output = ClassList;

	fn add(self, rhs: &'static str) -> Self::Output {
		let mut list = ClassList(self.0.to_owned());
		list.push(rhs);
		list
	}
}

impl std::ops::Add<ClassToken> for ClassList {
	type Output = Self;

	fn add(mut self, rhs: ClassToken) -> Self::Output {
		self.push(rhs.0);
		self
	}
}

impl std::ops::Add<&'static str> for ClassList {
	type Output = Self;

	fn add(mut self, rhs: &'static str) -> Self::Output {
		self.push(rhs);
		self
	}
}

impl From<ClassToken> for Cow<'static, str> {
	fn from(value: ClassToken) -> Self {
		Self::Borrowed(value.0)
	}
}

impl From<ClassList> for Cow<'static, str> {
	fn from(value: ClassList) -> Self {
		Self::Owned(value.0)
	}
}

#[derive(Clone, Debug, PartialEq, Eq)]
struct StyleVarValue {
	name: &'static str,
	value: String,
}

/// Source-ordered runtime overrides for generated component variables.
#[derive(Clone, Debug, PartialEq, Eq)]
pub struct StyleVars {
	slots: Vec<Option<StyleVarValue>>,
}

impl StyleVars {
	/// Creates the fixed number of generated variable slots.
	#[doc(hidden)]
	pub fn with_slots(len: usize) -> Self {
		Self {
			slots: vec![None; len],
		}
	}

	/// Replaces one generated variable slot with a validated value.
	#[doc(hidden)]
	pub fn set<V: StyleValue>(&mut self, index: usize, name: &'static str, value: V) {
		let mut serialized = String::new();
		value.write_css_value(&mut serialized);
		let slot = self
			.slots
			.get_mut(index)
			.expect("generated style variable index is in bounds");
		*slot = Some(StyleVarValue {
			name,
			value: serialized,
		});
	}

	/// Replaces one generated variable slot after enforcing a nonnegative numeric value.
	#[doc(hidden)]
	pub fn set_non_negative<V: StyleValue>(&mut self, index: usize, name: &'static str, value: V) {
		assert!(
			value.numeric_value().is_some_and(|number| number >= 0.0),
			"generated style variable requires a nonnegative numeric value"
		);
		self.set(index, name, value);
	}

	/// Replaces one generated variable slot after enforcing an inclusive numeric range.
	#[doc(hidden)]
	pub fn set_inclusive_range<V: StyleValue>(
		&mut self,
		index: usize,
		name: &'static str,
		minimum: i16,
		maximum: i16,
		value: V,
	) {
		assert!(
			value.numeric_value().is_some_and(|number| {
				number >= f64::from(minimum) && number <= f64::from(maximum)
			}),
			"generated style variable requires a value in the inclusive range {minimum}..={maximum}"
		);
		self.set(index, name, value);
	}
}

impl From<StyleVars> for Cow<'static, str> {
	fn from(value: StyleVars) -> Self {
		if value.slots.iter().all(Option::is_none) {
			return Self::Borrowed("");
		}

		let mut output = String::new();
		for slot in value.slots.into_iter().flatten() {
			output.push_str(slot.name);
			output.push_str(": ");
			output.push_str(&slot.value);
			output.push(';');
		}
		Self::Owned(output)
	}
}
